127	          var ws = window.__lwpWs;
128	          if (!ws || ws.readyState !== 1) { reject(new Error('WS not ready')); return; }
129	          var mid = Date.now() + ' ' + (++window.__lwpSeq);
130	          var req = JSON.stringify({ lwp: lwpPath, headers: { mid: mid }, body: body });
131	          window.__lwpPending[mid] = { resolve: resolve, reject: reject };
132	          ws.send(req);
133	          setTimeout(function() {
134	            if (window.__lwpPending[mid]) { delete window.__lwpPending[mid]; reject(new Error('timeout')); }
135	          }, 30000);
136	        });
137	      };
138	
139	      return JSON.stringify({ installed: true });
140	    })()
141	  `);
142	  await sleep(2000);
143	  log('收发器已安装');
144	
145	  // ========== Step 3: 确认 WS 已捕获 ==========
146	  await evaluate(sessionId, client, 4, `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`);
