171	  const convData = evalResults[6];
172	  log(`会话总数: ${convData.total}`);
173	  const allConvs = convData.convs;
174	
175	  // 创建输出目录
176	  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
177	
178	  // 检查已抓取的会话（断点续传）
179	  const fetched = new Set();
180	  if (fs.existsSync(DATA_DIR)) {
181	    fs.readdirSync(DATA_DIR).forEach(f => {
182	      if (f.endsWith('.json')) fetched.add(f.replace('.json', ''));
183	    });
184	  }
