186	  log(`待抓取: ${toFetch.length} / 已完成: ${fetched.size}`);
187	
188	  // ========== Step 5: 批量抓取 ==========
189	  let totalMsgs = 0;
190	  let errors = 0;
191	  let msgIdCounter = 100;
192	
193	  // 先做一个快速测试，验证 LWP 能正常工作
194	  if (toFetch.length > 0) {
195	    log('测试 LWP 请求...');
196	    const testCid = toFetch[0].cid;
197	    await evaluate(sessionId, client, 7, `
198	      (async function() {
199	        try {
200	          var result = await window.__lwpRequest('/r/MessageManager/listUserMessages', ['${testCid}', false, 9007199254740991, ${MSG_COUNT}, false]);
201	          return JSON.stringify({ ok: true, code: result.code, msgCount: result.body ? result.body.userMessageModels ? result.body.userMessageModels.length : 0 : 0 });
202	        } catch(e) {
203	          return JSON.stringify({ ok: false, error: e.message });
204	        }
205	      })()
206	    `, true);
207	    await sleep(5000);
208	    log('LWP 测试结果: ' + JSON.stringify(evalResults[7]));
209	  }
210	
211	  for (let i = 0; i < toFetch.length; i += BATCH_SIZE) {
212	    const batch = toFetch.slice(i, i + BATCH_SIZE);
213	    log(`批次 ${Math.floor(i / BATCH_SIZE) + 1}/${Math.ceil(toFetch.length / BATCH_SIZE)} (${i + 1}-${Math.min(i + BATCH_SIZE, toFetch.length)})`);
214	
215	    for (const conv of batch) {
216	      try {
217	        const cid = conv.cid;
218	        const safeName = sanitizeFilename(cid);
219	
220	        const allMessages = [];
221	        let cursor = 9007199254740991;
222	        let pageNum = 0;
223	
224	        while (pageNum < MAX_PAGES) {
225	          const msgId = msgIdCounter++;
226	          evalResults[msgId] = undefined;
227	
228	          await evaluate(sessionId, client, msgId, `
229	            (async function() {
230	              try {
231	                var result = await window.__lwpRequest('/r/MessageManager/listUserMessages', ['${cid}', false, ${cursor}, ${MSG_COUNT}, false]);
232	                return JSON.stringify(result);
233	              } catch(e) {
234	                return JSON.stringify({ __error: e.message });
235	              }
236	            })()
237	          `, true);
238	          await sleep(2000);
239	
240	          const raw = evalResults[msgId];
241	          if (!raw || raw.__error) {
242	            if (raw && raw.__error === 'timeout') { log(`  [${conv.name}] 超时，跳过`); }
243	            break;
244	          }
245	
246	          let response;
247	          try {
248	            response = typeof raw === 'string' ? JSON.parse(raw) : raw;
249	          } catch (e) { log(`  [${conv.name}] 响应解析失败`); break; }
250	
251	          if (response.code !== 200) break;
252	
253	          const body = response.body;
254	          if (!body || !body.userMessageModels || body.userMessageModels.length === 0) break;
255	
256	          const msgs = body.userMessageModels;
257	          allMessages.push(...msgs);
258	
259	          if (msgs.length < MSG_COUNT || !body.nextCursor) break;
260	          cursor = body.nextCursor;
261	          pageNum++;
262	        }
263	
264	        const output = {
265	          cid: cid,
266	          name: conv.name,
267	          fetchedAt: new Date().toISOString(),
268	          totalMessages: allMessages.length,
269	          messages: allMessages
270	        };
271	
272	        fs.writeFileSync(path.join(DATA_DIR, safeName + '.json'), JSON.stringify(output, null, 2));
273	        totalMsgs += allMessages.length;
274	        if (allMessages.length > 0) {
275	          log(`  [${conv.name}] ${allMessages.length} 条`);
276	        }
277	
278	      } catch (e) {
279	        errors++;
280	        if (errors <= 5) log(`  [${conv.name}] 错误: ${e.message}`);
281	      }
282	    }
283	
284	    log(`  批次完成，累计 ${totalMsgs} 条消息，${errors} 个错误`);
285	    if (i + BATCH_SIZE < toFetch.length) await sleep(BATCH_DELAY);
286	  }
287	
288	  // ========== Step 6: 汇总报告 ==========
289	  log('');
290	  log('========== 抓取完成 ==========');
291	  log(`总会话: ${allConvs.length}`);
292	  log(`本次抓取: ${toFetch.length}`);
293	  log(`总消息数: ${totalMsgs}`);
294	  log(`错误数: ${errors}`);
295	  log(`输出目录: ${DATA_DIR}`);
296	
297	  // 生成汇总
298	  const summary = {
299	    exportedAt: new Date().toISOString(),
300	    totalConversations: allConvs.length,
301	    fetchedConversations: toFetch.length,
302	    totalMessages: totalMsgs,
303	    errors: errors,
304	    dataDir: DATA_DIR
305	  };
306	  fs.writeFileSync(
307	    path.join(DATA_DIR, '_summary.json'),
308	    JSON.stringify(summary, null, 2)
309	  );
310	
311	  process.exit(0);
312	})().catch(e => { log('致命错误: ' + e.message); process.exit(1); });
313	
314	// ========== Helper ==========
315	
316	function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
317	
318	async function evaluate(sessionId, client, id, expression, awaitPromise) {
319	  await client.send('Target.sendMessageToTarget', {
320	    sessionId,
321	    message: JSON.stringify({
322	      id,
323	      method: 'Runtime.evaluate',
324	      params: { expression, awaitPromise: !!awaitPromise }
325	    })
326	  });
327	}
328	
329	function sanitizeFilename(cid) {
330	  return cid.replace(/[<>:"/\\|?*#@]/g, '_').substring(0, 200);
331	}
